class Solution:
    def minCut(self, s: str) -> int:
        n = len(s)
        is_pal = [[False] * n for _ in range(n)]
        for i in range(n - 1, -1, -1):
            for j in range(i, n):
                if s[i] == s[j] and (j - i <= 2 or is_pal[i + 1][j - 1]):
                    is_pal[i][j] = True
        cuts = list(range(-1, n))
        for j in range(1, n):
            for i in range(j + 1):
                if is_pal[i][j]:
                    cuts[j + 1] = min(cuts[j + 1], cuts[i] + 1)
        return cuts[n]

solution_js:
var minCut = function(s) {
    const n = s.length;
    const isPal = Array.from({length: n}, () => new Array(n).fill(false));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = i; j < n; j++) {
            if (s[i] === s[j] && (j - i <= 2 || isPal[i + 1][j - 1])) {
                isPal[i][j] = true;
            }
        }
    }
    const cuts = Array.from({length: n + 1}, (_, k) => k - 1);
    for (let j = 1; j < n; j++) {
        for (let i = 0; i <= j; i++) {
            if (isPal[i][j]) {
                cuts[j + 1] = Math.min(cuts[j + 1], cuts[i] + 1);
            }
        }
    }
    return cuts[n];
};

