class Solution:
    def maxTurbulenceSize(self, arr: List[int]) -> int:
        n = len(arr)
        result = 1
        left = 0
        for right in range(1, n):
            c = (arr[right] > arr[right - 1]) - (arr[right] < arr[right - 1])
            if right >= 2:
                prev_c = (arr[right - 1] > arr[right - 2]) - (arr[right - 1] < arr[right - 2])
                if c == 0:
                    left = right
                elif c == prev_c:
                    left = right - 1
            elif c == 0:
                left = right
            result = max(result, right - left + 1)
        return result

solution_js:
var maxTurbulenceSize = function(arr) {
    const n = arr.length;
    let result = 1, left = 0;
    for (let right = 1; right < n; right++) {
        const c = Math.sign(arr[right] - arr[right - 1]);
        if (right >= 2) {
            const prevC = Math.sign(arr[right - 1] - arr[right - 2]);
            if (c === 0) left = right;
            else if (c === prevC) left = right - 1;
        } else if (c === 0) {
            left = right;
        }
        result = Math.max(result, right - left + 1);
    }
    return result;
};

