class Solution:
    def maxScore(self, cardPoints: List[int], k: int) -> int:
        n = len(cardPoints)
        total = sum(cardPoints)
        if k == n:
            return total
        window_size = n - k
        window_sum = sum(cardPoints[:window_size])
        min_window = window_sum
